public class EscrowContract {
 private String buyer;
 private String seller;
 private String arbiter;
 private int funds;

 public EscrowContract(String buyer, String seller, String arbiter) {
 this.buyer = buyer;
 this.seller = seller;
 this.arbiter = arbiter;
 this.funds = 0;
 }

 public void releaseFundsToSeller() {
 if (buyer.equals("buyer") || arbiter.equals("arbiter")) {
 funds = 0;
 System.out.println("Funds released to seller");
 } else {
 System.out.println("Not authorized");
 }
 }

 public void refundBuyer() {
 if (seller.equals("seller") || arbiter.equals("arbiter")) {
 funds = 0;
 System.out.println("Funds refunded to buyer");
 } else {
 System.out.println("Not authorized");
 }
 }
}
